(function(w){"use strict";const ID="iso-week";function p(v){if(!/^\d{4}-\d{2}-\d{2}$/.test(v||""))return null;const a=v.split("-").map(Number),d=new Date(Date.UTC(a[0],a[1]-1,a[2]));return d.getUTCFullYear()===a[0]&&d.getUTCMonth()===a[1]-1&&d.getUTCDate()===a[2]?d:null}function compute(x){const d=p(x.date);if(!d)return{error:"날짜를 올바르게 입력해 주세요."};const t=new Date(d);let day=t.getUTCDay();if(day===0)day=7;t.setUTCDate(t.getUTCDate()+4-day);const year=t.getUTCFullYear(),start=new Date(Date.UTC(year,0,1)),week=Math.ceil((((t-start)/86400000)+1)/7);return{week,isoYear:year,label:year+'년 '+week+'주차'}}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label>날짜</label><input class="hm-calc-input" type="date"></div><p class="hm-calc-hint">ISO 8601 기준 주차를 사용합니다.</p><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">주차 계산</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const input=root.querySelector("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");input.value=api.localDateString();go.addEventListener("click",()=>{const r=compute({date:input.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("ISO 주차",r.label));});}
w.HM_CALC.register(ID,{compute,render});})(window);
